package setup

import (
	_ "embed"
	"log"
	"sync"

	"gopkg.in/yaml.v3"
)

//go:embed setup.yaml
var setupYaml []byte

type MarketCreation struct {
	InitialMarketProbability   float64 `yaml:"initialMarketProbability"`
	InitialMarketSubsidization int64   `yaml:"initialMarketSubsidization"`
	InitialMarketYes           int64   `yaml:"initialMarketYes"`
	InitialMarketNo            int64   `yaml:"initialMarketNo"`
	MinimumFutureHours         float64 `yaml:"minimumFutureHours"`
}

type MarketIncentives struct {
	CreateMarketCost int64 `yaml:"createMarketCost"`
	TraderBonus      int64 `yaml:"traderBonus"`
}

type User struct {
	InitialAccountBalance int64 `yaml:"initialAccountBalance"`
	MaximumDebtAllowed    int64 `yaml:"maximumDebtAllowed"`
}

type BetFees struct {
	InitialBetFee int64 `yaml:"initialBetFee"`
	BuySharesFee  int64 `yaml:"buySharesFee"`
	SellSharesFee int64 `yaml:"sellSharesFee"`
}

type Betting struct {
	MinimumBet     int64   `yaml:"minimumBet"`
	MaxDustPerSale int64   `yaml:"maxDustPerSale"`
	BetFees        BetFees `yaml:"betFees"`
}

type Economics struct {
	MarketCreation   MarketCreation   `yaml:"marketcreation"`
	MarketIncentives MarketIncentives `yaml:"marketincentives"`
	User             User             `yaml:"user"`
	Betting          Betting          `yaml:"betting"`
}

type FrontendCharts struct {
	SigFigs int `yaml:"sigFigs"`
}

type Frontend struct {
	Charts FrontendCharts `yaml:"charts"`
}

type EconomicConfig struct {
	Economics Economics `yaml:"economics"`
	Frontend  Frontend  `yaml:"frontend"`
}

var economicConfig *EconomicConfig

const (
	minChartSigFigs     = 2
	maxChartSigFigs     = 9
	defaultChartSigFigs = 4
)

// load once as a singleton pattern
var once sync.Once

func LoadEconomicsConfig() (*EconomicConfig, error) {
	once.Do(func() {
		economicConfig = &EconomicConfig{}
		err := yaml.Unmarshal(setupYaml, economicConfig)
		if err != nil {
			log.Println("Error parsing YAML config:", err) // Log here or just pass the error up
			return
		}
	})
	return economicConfig, nil
}

// EconConfigLoader allows functions to use this type as a parameter to load an EconomicConfig Dependency
type EconConfigLoader func() *EconomicConfig

// EconomicsConfig returns the entire config for the applications economics
func EconomicsConfig() *EconomicConfig {
	return economicConfig
}

func mustLoadEconomicsConfig() {
	economicConfig = &EconomicConfig{}
	err := yaml.Unmarshal(setupYaml, economicConfig)
	if err != nil {
		log.Fatal("Error parsing YAML config:", err) // If the config cannot be loaded, the application cannot recover.
	}
}

func init() {
	mustLoadEconomicsConfig()
}

// ChartSigFigs returns a clamped significant figures value for chart formatting.
func ChartSigFigs() int {
	if economicConfig == nil {
		mustLoadEconomicsConfig()
	}

	sigFigs := economicConfig.Frontend.Charts.SigFigs
	if sigFigs == 0 {
		sigFigs = defaultChartSigFigs
	}

	if sigFigs < minChartSigFigs {
		return minChartSigFigs
	}
	if sigFigs > maxChartSigFigs {
		return maxChartSigFigs
	}
	return sigFigs
}

package app

import (
	"time"

	"socialpredict/setup"

	"gorm.io/gorm"

	// Domain services
	analytics "socialpredict/internal/domain/analytics"
	dbets "socialpredict/internal/domain/bets"
	dmarkets "socialpredict/internal/domain/markets"
	positionsmath "socialpredict/internal/domain/math/positions"
	"socialpredict/internal/domain/math/probabilities/wpam"
	dusers "socialpredict/internal/domain/users"

	// Repositories
	rbets "socialpredict/internal/repository/bets"
	rmarkets "socialpredict/internal/repository/markets"
	rusers "socialpredict/internal/repository/users"

	// Handlers
	hmarkets "socialpredict/handlers/markets"
	authsvc "socialpredict/internal/service/auth"
	"socialpredict/security"
)

// Clock interface for testability
type Clock interface {
	Now() time.Time
}

// SystemClock implements Clock using system time
type SystemClock struct{}

func (SystemClock) Now() time.Time {
	return time.Now()
}

// Container holds all the application dependencies
type Container struct {
	db     *gorm.DB
	config *setup.EconomicConfig
	clock  Clock

	// Repositories
	marketsRepo   rmarkets.GormRepository
	usersRepo     rusers.GormRepository
	analyticsRepo analytics.GormRepository
	betsRepo      rbets.GormRepository

	// Domain services
	analyticsService *analytics.Service
	marketsService   *dmarkets.Service
	usersService     *dusers.Service
	betsService      *dbets.Service
	authService      *authsvc.AuthService

	// Handlers
	marketsHandler *hmarkets.Handler
}

// NewContainer creates a new dependency injection container
func NewContainer(db *gorm.DB, config *setup.EconomicConfig) *Container {
	return &Container{
		db:     db,
		config: config,
		clock:  SystemClock{},
	}
}

// InitializeRepositories sets up all repository implementations
func (c *Container) InitializeRepositories() {
	c.marketsRepo = *rmarkets.NewGormRepository(c.db)
	c.usersRepo = *rusers.NewGormRepository(c.db)
	c.betsRepo = *rbets.NewGormRepository(c.db)
}

// InitializeServices sets up all domain services with their dependencies
func (c *Container) InitializeServices() {
	// Users service depends on users repository and configuration
	securityService := security.NewSecurityService()
	configLoader := func() *setup.EconomicConfig { return c.config }

	wpamSeeds := wpam.Seeds{
		InitialProbability:     c.config.Economics.MarketCreation.InitialMarketProbability,
		InitialSubsidization:   c.config.Economics.MarketCreation.InitialMarketSubsidization,
		InitialYesContribution: c.config.Economics.MarketCreation.InitialMarketYes,
		InitialNoContribution:  c.config.Economics.MarketCreation.InitialMarketNo,
	}
	wpamCalculator := wpam.NewProbabilityCalculator(wpam.StaticSeedProvider{Value: wpamSeeds})
	positionProbabilityProvider := positionsmath.NewWPAMProbabilityProvider(wpamCalculator)
	positionCalculator := positionsmath.NewPositionCalculator(
		positionsmath.WithProbabilityProvider(positionProbabilityProvider),
	)

	positionCalcAdapter := analytics.NewMarketPositionCalculator(positionCalculator)

	c.analyticsRepo = *analytics.NewGormRepository(c.db, analytics.WithRepositoryPositionCalculator(positionCalcAdapter))
	c.analyticsService = analytics.NewService(&c.analyticsRepo, configLoader, analytics.WithPositionCalculator(positionCalcAdapter))
	c.usersService = dusers.NewService(&c.usersRepo, c.analyticsService, securityService.Sanitizer)
	c.authService = authsvc.NewAuthService(c.usersService)

	// Markets service depends on markets repository and users service
	marketsConfig := dmarkets.Config{
		MinimumFutureHours: c.config.Economics.MarketCreation.MinimumFutureHours,
		CreateMarketCost:   c.config.Economics.MarketIncentives.CreateMarketCost,
		MaximumDebtAllowed: c.config.Economics.User.MaximumDebtAllowed,
	}

	c.marketsService = dmarkets.NewService(
		&c.marketsRepo,
		c.usersService,
		c.clock,
		marketsConfig,
		dmarkets.WithProbabilityEngine(dmarkets.DefaultProbabilityEngine(wpamCalculator)),
	)

	c.betsService = dbets.NewService(&c.betsRepo, c.marketsService, c.usersService, c.config, c.clock)
}

// InitializeHandlers sets up all HTTP handlers with their service dependencies
func (c *Container) InitializeHandlers() {
	c.marketsHandler = hmarkets.NewHandler(c.marketsService, c.authService)
}

// Initialize sets up the entire dependency graph
func (c *Container) Initialize() {
	c.InitializeRepositories()
	c.InitializeServices()
	c.InitializeHandlers()
}

// GetMarketsHandler returns the markets HTTP handler
func (c *Container) GetMarketsHandler() *hmarkets.Handler {
	return c.marketsHandler
}

// GetUsersService returns the users domain service
func (c *Container) GetUsersService() *dusers.Service {
	return c.usersService
}

// GetAnalyticsService returns the analytics domain service
func (c *Container) GetAnalyticsService() *analytics.Service {
	return c.analyticsService
}

// GetMarketsService returns the markets domain service
func (c *Container) GetMarketsService() *dmarkets.Service {
	return c.marketsService
}

// GetBetsService returns the bets domain service
func (c *Container) GetBetsService() *dbets.Service {
	return c.betsService
}

// GetAuthService returns the authentication façade
func (c *Container) GetAuthService() *authsvc.AuthService {
	return c.authService
}

// BuildApplication creates a fully wired application container
func BuildApplication(db *gorm.DB, config *setup.EconomicConfig) *Container {
	container := NewContainer(db, config)
	container.Initialize()
	return container
}

package setup

import (
	"encoding/json"
	"net/http"
	"socialpredict/setup"
)

func GetSetupHandler(loadEconomicsConfig func() (*setup.EconomicConfig, error)) func(w http.ResponseWriter, r *http.Request) {
	return func(w http.ResponseWriter, r *http.Request) {
		appConfig, err := loadEconomicsConfig()
		if err != nil {
			http.Error(w, "Failed to load economic config", http.StatusInternalServerError)
			return
		}

		w.Header().Set("Content-Type", "application/json")
		err = json.NewEncoder(w).Encode(appConfig.Economics)
		if err != nil {
			http.Error(w, "Failed to encode response", http.StatusInternalServerError)
		}
	}
}

type frontendChartsResponse struct {
	SigFigs int `json:"sigFigs"`
}

type frontendConfigResponse struct {
	Charts frontendChartsResponse `json:"charts"`
}

func GetFrontendSetupHandler(loadEconomicsConfig func() (*setup.EconomicConfig, error)) func(w http.ResponseWriter, r *http.Request) {
	return func(w http.ResponseWriter, r *http.Request) {
		_, err := loadEconomicsConfig()
		if err != nil {
			http.Error(w, "Failed to load frontend config", http.StatusInternalServerError)
			return
		}

		response := frontendConfigResponse{
			Charts: frontendChartsResponse{
				SigFigs: setup.ChartSigFigs(),
			},
		}

		w.Header().Set("Content-Type", "application/json")
		if err := json.NewEncoder(w).Encode(response); err != nil {
			http.Error(w, "Failed to encode frontend setup response", http.StatusInternalServerError)
			return
		}
	}
}

